import urllib.request
import json

# Search for real GDP constant prices
indicators = [
    'NY.GDP.MKTP.KD',  # GDP (constant 2015 US$)
    'NY.GDP.MKTP.KN',  # GDP (constant LCU)
    'NY.GDP.PCAP.KD',  # GDP per capita (constant 2015 US$)
]

for indicator in indicators:
    url = f'https://api.worldbank.org/v2/country/GEO/indicator/{indicator}?format=json&per_page=100'
    try:
        req = urllib.request.Request(url, headers={'User-Agent': 'Mozilla/5.0'})
        response = urllib.request.urlopen(req, timeout=30)
        data = json.loads(response.read().decode('utf-8'))
        if data and len(data) > 1 and data[1]:
            print(f"\n{indicator}:")
            for item in data[1][:5]:
                print(f"  {item['date']}: {item['value']}")
            print(f"  Total records: {data[0]['total']}")
        else:
            print(f"\n{indicator}: No data")
    except Exception as e:
        print(f"{indicator}: Error - {e}")
EOF
